CREATE TABLE IF NOT EXISTS categories (id INTEGER PRIMARY KEY AUTOINCREMENT,name_ar TEXT NOT NULL,name_en TEXT NOT NULL,description TEXT,parent_id INTEGER REFERENCES categories(id) ON DELETE SET NULL,order_index INTEGER NOT NULL DEFAULT 0,icon TEXT,created_at TEXT NOT NULL DEFAULT (datetime('now')),updated_at TEXT NOT NULL DEFAULT (datetime('now')));
CREATE TABLE IF NOT EXISTS sub_topics (id INTEGER PRIMARY KEY AUTOINCREMENT,category_id INTEGER NOT NULL REFERENCES categories(id) ON DELETE CASCADE,title_ar TEXT NOT NULL,title_en TEXT NOT NULL,summary TEXT,rich_text_content TEXT NOT NULL DEFAULT '{}',keywords_array TEXT NOT NULL DEFAULT '[]',order_index INTEGER NOT NULL DEFAULT 0,is_published INTEGER NOT NULL DEFAULT 0,created_at TEXT NOT NULL DEFAULT (datetime('now')),updated_at TEXT NOT NULL DEFAULT (datetime('now')));
CREATE TABLE IF NOT EXISTS testaments (id INTEGER PRIMARY KEY AUTOINCREMENT,name_ar TEXT NOT NULL,name_en TEXT NOT NULL,order_index INTEGER NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS books (id INTEGER PRIMARY KEY AUTOINCREMENT,testament_id INTEGER NOT NULL REFERENCES testaments(id) ON DELETE CASCADE,name_ar TEXT NOT NULL,name_en TEXT NOT NULL,book_order INTEGER NOT NULL,chapter_count INTEGER NOT NULL DEFAULT 1);
CREATE TABLE IF NOT EXISTS chapters (id INTEGER PRIMARY KEY AUTOINCREMENT,book_id INTEGER NOT NULL REFERENCES books(id) ON DELETE CASCADE,chapter_number INTEGER NOT NULL,title_ar TEXT,title_en TEXT,summary TEXT,UNIQUE(book_id,chapter_number));
CREATE TABLE IF NOT EXISTS image_sets (id INTEGER PRIMARY KEY AUTOINCREMENT,entity_type TEXT NOT NULL,entity_id INTEGER NOT NULL,title TEXT NOT NULL,source_reference TEXT,created_at TEXT NOT NULL DEFAULT (datetime('now')));
CREATE TABLE IF NOT EXISTS images (id INTEGER PRIMARY KEY AUTOINCREMENT,image_set_id INTEGER NOT NULL REFERENCES image_sets(id) ON DELETE CASCADE,file_name TEXT NOT NULL,file_path TEXT NOT NULL,caption TEXT,source_reference TEXT,created_at TEXT NOT NULL DEFAULT (datetime('now')));
CREATE TABLE IF NOT EXISTS videos (id INTEGER PRIMARY KEY AUTOINCREMENT,entity_type TEXT NOT NULL,entity_id INTEGER NOT NULL,title TEXT NOT NULL,video_type TEXT NOT NULL,url TEXT NOT NULL,description TEXT,created_at TEXT NOT NULL DEFAULT (datetime('now')));
CREATE TABLE IF NOT EXISTS texts (id INTEGER PRIMARY KEY AUTOINCREMENT,entity_type TEXT NOT NULL,entity_id INTEGER NOT NULL,title TEXT NOT NULL,content_json TEXT NOT NULL DEFAULT '{}',track_type TEXT NOT NULL,created_at TEXT NOT NULL DEFAULT (datetime('now')));
CREATE TABLE IF NOT EXISTS cross_links (id INTEGER PRIMARY KEY AUTOINCREMENT,from_type TEXT NOT NULL,from_id INTEGER NOT NULL,to_type TEXT NOT NULL,to_id INTEGER NOT NULL,note TEXT,created_at TEXT NOT NULL DEFAULT (datetime('now')));
CREATE TABLE IF NOT EXISTS search_index (id INTEGER PRIMARY KEY AUTOINCREMENT,entity_type TEXT NOT NULL,entity_id INTEGER NOT NULL,title TEXT NOT NULL,keywords TEXT NOT NULL DEFAULT '[]',content TEXT NOT NULL DEFAULT '',track_type TEXT NOT NULL DEFAULT 'thematic');
CREATE VIRTUAL TABLE IF NOT EXISTS fts_index USING fts5(entity_type, entity_id UNINDEXED, title, keywords, content, track_type);
